1	import { useState, useEffect } from 'react';
2	import { useNavigate, useParams } from 'react-router-dom';
3	import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
4	import { createCollectible, getCollectible, updateCollectible } from '../api/collectibles';
5	
6	export function CollectibleFormPage() {
7	  const { id } = useParams<{ id: string }>();
8	  const isEdit = !!id;
9	  const navigate = useNavigate();
10	  const queryClient = useQueryClient();
11	
12	  const [form, setForm] = useState({
13	    title: '',
14	    description: '',
15	    price_cents: 0,
16	    currency: 'USD',
17	    contract_address: '',
18	    chain_id: 0,
19	    token_id: '',
20	    metadata_uri: '',
21	    image_url: '',
22	  });
23	  const [error, setError] = useState('');
24	
25	  const { data: editData } = useQuery({
26	    queryKey: ['collectible', id],
27	    queryFn: () => getCollectible(id!).then((r) => r.data),
28	    enabled: isEdit,
29	  });
30	
31	  useEffect(() => {
32	    if (editData) {
33	      const c = editData.collectible;
34	      setForm({
35	        title: c.title,
36	        description: c.description,
37	        price_cents: c.price_cents,
38	        currency: c.currency,
39	        contract_address: c.contract_address || '',
40	        chain_id: c.chain_id || 0,
41	        token_id: c.token_id || '',
42	        metadata_uri: c.metadata_uri || '',
43	        image_url: c.image_url || '',
44	      });
45	    }
46	  }, [editData]);
47	
48	  const createMutation = useMutation({
49	    mutationFn: () => createCollectible({
50	      ...form,
51	      price_cents: Number(form.price_cents),
52	      chain_id: form.chain_id || undefined,
53	      token_id: form.token_id || undefined,
54	    }),
55	    onSuccess: (res) => {
56	      queryClient.invalidateQueries({ queryKey: ['collectibles'] });
57	      navigate(`/catalog/${res.data.id}`);
58	    },
59	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
60	  });
61	
62	  const updateMutation = useMutation({
63	    mutationFn: () => updateCollectible(id!, {
64	      title: form.title,
65	      description: form.description,
66	      price_cents: Number(form.price_cents),
67	      image_url: form.image_url,
68	      metadata_uri: form.metadata_uri,
69	    }),
70	    onSuccess: () => {
71	      queryClient.invalidateQueries({ queryKey: ['collectible', id] });
72	      navigate(`/catalog/${id}`);
73	    },
74	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
75	  });
76	
77	  const handleSubmit = (e: React.FormEvent) => {
78	    e.preventDefault();
79	    if (isEdit) updateMutation.mutate();
80	    else createMutation.mutate();
81	  };
82	
83	  return (
84	    <div className="max-w-2xl mx-auto">
85	      <h1 className="text-2xl font-bold mb-6">{isEdit ? 'Edit Listing' : 'Create Listing'}</h1>
86	
87	      <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-4">
88	        <div>
89	          <label className="block text-sm font-medium text-gray-700 mb-1">Title *</label>
90	          <input type="text" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })}
91	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required maxLength={300} />
92	        </div>
93	        <div>
94	          <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
95	          <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })}
96	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" rows={4} maxLength={5000} />
97	        </div>
98	        <div className="grid grid-cols-2 gap-4">
99	          <div>
100	            <label className="block text-sm font-medium text-gray-700 mb-1">Price (cents) *</label>
101	            <input type="number" value={form.price_cents} onChange={(e) => setForm({ ...form, price_cents: Number(e.target.value) })}
102	              className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required min={1} />
103	          </div>
104	          <div>
105	            <label className="block text-sm font-medium text-gray-700 mb-1">Currency</label>
106	            <input type="text" value={form.currency} onChange={(e) => setForm({ ...form, currency: e.target.value })}
107	              className="w-full px-3 py-2 border rounded" maxLength={3} />
108	          </div>
109	        </div>
110	        <div>
111	          <label className="block text-sm font-medium text-gray-700 mb-1">Image URL</label>
112	          <input type="url" value={form.image_url} onChange={(e) => setForm({ ...form, image_url: e.target.value })}
113	            className="w-full px-3 py-2 border rounded" />
114	        </div>
115	
116	        {!isEdit && (
117	          <>
118	            <div>
119	              <label className="block text-sm font-medium text-gray-700 mb-1">Contract Address</label>
120	              <input type="text" value={form.contract_address} onChange={(e) => setForm({ ...form, contract_address: e.target.value })}
121	                className="w-full px-3 py-2 border rounded font-mono text-sm" maxLength={42} />
122	            </div>
123	            <div>
124	              <label className="block text-sm font-medium text-gray-700 mb-1">Metadata URI</label>
125	              <input type="url" value={form.metadata_uri} onChange={(e) => setForm({ ...form, metadata_uri: e.target.value })}
126	                className="w-full px-3 py-2 border rounded" />
127	            </div>
128	            <div className="grid grid-cols-2 gap-4">
129	              <div>
130	                <label className="block text-sm font-medium text-gray-700 mb-1">Chain ID</label>
131	                <input type="number" value={form.chain_id || ''} onChange={(e) => setForm({ ...form, chain_id: Number(e.target.value) })}
132	                  className="w-full px-3 py-2 border rounded" min={1} placeholder="e.g. 1" />
133	              </div>
134	              <div>
135	                <label className="block text-sm font-medium text-gray-700 mb-1">Token ID</label>
136	                <input type="text" value={form.token_id} onChange={(e) => setForm({ ...form, token_id: e.target.value })}
137	                  className="w-full px-3 py-2 border rounded font-mono text-sm" placeholder="Auto-generated if empty" />
138	              </div>
139	            </div>
140	            <p className="text-xs text-gray-400">Chain ID and Token ID are required when Contract Address is provided, optional otherwise.</p>
141	          </>
142	        )}
143	
144	        {error && <div className="text-sm text-red-600 bg-red-50 p-2 rounded">{error}</div>}
145	
146	        <div className="flex gap-2">
147	          <button
148	            type="submit"
149	            disabled={createMutation.isPending || updateMutation.isPending || !form.title || !form.price_cents}
150	            className="px-6 py-2 bg-primary-600 text-white rounded hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
151	          >
152	            {createMutation.isPending || updateMutation.isPending
153	              ? (isEdit ? 'Updating...' : 'Creating...')
154	              : (isEdit ? 'Update' : 'Create Listing')}
155	          </button>
156	          <button type="button" onClick={() => navigate(-1)} className="px-6 py-2 bg-gray-100 rounded hover:bg-gray-200">Cancel</button>
157	        </div>
158	      </form>
159	    </div>
160	  );
161	}
162	
