1	import api from './client';
2	import type { Collectible, CollectibleTxHistory, PaginatedResponse } from '../types';
3	
4	export const listCollectibles = (page = 1, pageSize = 20, status = 'published') =>
5	  api.get<PaginatedResponse<Collectible>>('/collectibles', { params: { page, page_size: pageSize, status } });
6	
7	export const listMyCollectibles = (page = 1, pageSize = 20) =>
8	  api.get<PaginatedResponse<Collectible>>('/collectibles/mine', { params: { page, page_size: pageSize } });
9	
10	export const getCollectible = (id: string) =>
11	  api.get<{ collectible: Collectible; transaction_history: CollectibleTxHistory[] }>(`/collectibles/${id}`);
12	
13	export const createCollectible = (data: {
14	  title: string;
15	  description: string;
16	  price_cents: number;
17	  currency?: string;
18	  contract_address?: string;
19	  chain_id?: number;
20	  token_id?: string;
21	  metadata_uri?: string;
22	  image_url?: string;
23	}) => api.post<Collectible>('/collectibles', data);
24	
25	export const updateCollectible = (id: string, data: Partial<Collectible>) =>
26	  api.patch<Collectible>(`/collectibles/${id}`, data);
27	
28	export const hideCollectible = (id: string, reason: string) =>
29	  api.patch(`/collectibles/${id}/hide`, { reason });
30	
31	export const publishCollectible = (id: string) =>
32	  api.patch(`/collectibles/${id}/publish`);
33	
