25	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
26		existing, err := s.orderStore.GetByIdempotencyKey(ctx, idempotencyKey)
27		if err != nil {
28			return nil, fmt.Errorf("check idempotency: %w", err)
29		}
30		if existing != nil {
31			return existing, nil
32		}
33	
34		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
35		if err != nil {
36			return nil, fmt.Errorf("get collectible: %w", err)
37		}
38		if collectible == nil {
39			return nil, dto.ErrNotFound
40		}
41		if collectible.Status != "published" {
42			return nil, dto.ErrNotFound
43		}
44		if collectible.SellerID == buyerID {
45			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
46			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
47		}
48	
49		tx, err := s.orderStore.BeginTx(ctx)
50		if err != nil {
51			return nil, fmt.Errorf("begin tx: %w", err)
52		}
53		defer tx.Rollback(ctx)
54	
55		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
56			return nil, fmt.Errorf("acquire lock: %w", err)
57		}
58	
59		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
60		if err != nil {
61			return nil, fmt.Errorf("check active orders: %w", err)
62		}
63		if hasActive {
64			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
65			return nil, dto.ErrOversold
66		}
67	
68		order := &model.Order{
69			IdempotencyKey:     idempotencyKey,
70			BuyerID:            buyerID,
71			CollectibleID:      req.CollectibleID,
72			SellerID:           collectible.SellerID,
73			Status:             model.OrderStatusPending,
74			PriceSnapshotCents: collectible.PriceCents,
75		}
76	
77		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
78			return nil, fmt.Errorf("create order: %w", err)
79		}
80	
81		transition := &model.OrderStateTransition{
82			OrderID:    order.ID,
83			FromStatus: "",
84			ToStatus:   model.OrderStatusPending,
85			ActorID:    buyerID,
86			Reason:     "order created",
87		}
88		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
89			return nil, fmt.Errorf("record transition: %w", err)
90		}
91	
92		if err := tx.Commit(ctx); err != nil {
93			return nil, fmt.Errorf("commit: %w", err)
94		}
95	
96		// Emit analytics event
97		s.emitEvent(ctx, &buyerID, "order_created", &req.CollectibleID)
98	
99		return order, nil
100	}
