	// Non-admin/compliance users can ONLY see published
	if !hasAdminOrCompliance(viewerRoles) {
		status = "published"
	}

	cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
	if cached, ok := s.cache.Get(cacheKey); ok {
