35		// Get users who have cancelled orders in the last 24 hours
36		// We check all users with recent cancellations
37		rows, err := orderStore.CountByStatus(ctx)
38		if err != nil {
39			return err
40		}
41		_ = rows // Using this as a health check
42	
43		// Query users with excessive cancellations directly
44		type userCancel struct {
45			UserID string
46			Count  int
47		}
48	
49		// This is done via a direct query through the order store
50		// For each user who has cancelled, check their count
51		// In practice, we'd add a specific store method, but for now we rely on the
52		// analytics events approach - each cancellation is also an analytics event
53		users, err := analyticsStore.GetDistinctUsersWithEvents(ctx, "order_cancelled", 24)
54		if err != nil {
55			return fmt.Errorf("get users with cancellations: %w", err)
