11	
12	func NotificationRetryJob(notifStore *store.NotificationStore, logger *zap.Logger) Job {
13		return Job{
14			Name:     "notification_retry",
15			Interval: 60 * time.Second,
16			Fn: func(ctx context.Context) error {
17				// 1. Deliver pending notifications
18				pending, err := notifStore.GetPendingForDelivery(ctx, 100)
19				if err != nil {
20					return fmt.Errorf("get pending notifications: %w", err)
21				}
22				for _, n := range pending {
23					// Simulate delivery — in a real system this would call an email/push service.
24					// For this LAN platform, marking as delivered is the delivery action.
25					if err := notifStore.UpdateRetryState(ctx, n.ID, "delivered", 0, nil); err != nil {
26						logger.Error("deliver notification failed", zap.String("id", n.ID.String()), zap.Error(err))
27					}
28				}
29	
30				// 2. Retry failed notifications with exponential backoff
31				failed, err := notifStore.GetFailedForRetry(ctx, 50)
32				if err != nil {
33					return fmt.Errorf("get failed notifications: %w", err)
34				}
35	
36				for _, n := range failed {
37					newRetryCount := n.RetryCount + 1
38					backoff := time.Duration(1<<uint(newRetryCount)) * time.Minute
39					nextRetry := time.Now().Add(backoff).Format(time.RFC3339)
40	
41					status := "delivered"
42					var nextRetryPtr *string
43					if newRetryCount >= n.MaxRetries {
44						status = "permanently_failed"
45					} else {
46						nextRetryPtr = &nextRetry
47					}
48	
49					if err := notifStore.UpdateRetryState(ctx, n.ID, status, newRetryCount, nextRetryPtr); err != nil {
50						logger.Error("retry notification failed", zap.String("id", n.ID.String()), zap.Error(err))
51					}
52				}
53				return nil
54			},
55		}
56	}
