1	package config
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/sha256"
7		"encoding/hex"
8		"encoding/json"
9		"fmt"
10		"os"
11	)
12	
13	type Config struct {
14		ListenAddr    string
15		DatabaseURL   string
16		JWTSigningKey []byte
17		AESMasterKey  []byte
18	}
19	
20	type secretsFile struct {
21		DatabaseURL   string `json:"database_url"`
22		JWTSigningKey string `json:"jwt_signing_key"`
23		AESMasterKey  string `json:"aes_master_key"`
24	}
25	
26	func Load() (*Config, error) {
27		listenAddr := os.Getenv("LISTEN_ADDR")
28		if listenAddr == "" {
29			listenAddr = ":8080"
30		}
31	
32		keyfile := os.Getenv("SECRETS_KEYFILE")
33		if keyfile != "" {
34			return loadFromKeyfile(listenAddr, keyfile)
35		}
36	
37		// Plaintext env vars only allowed in development mode
38		appEnv := os.Getenv("APP_ENV")
39		if appEnv != "" && appEnv != "development" {
40			return nil, fmt.Errorf("SECRETS_KEYFILE is required in %s mode; plaintext env vars only allowed when APP_ENV=development", appEnv)
41		}
42	
43		return loadFromEnv(listenAddr)
44	}
45	
46	func loadFromEnv(listenAddr string) (*Config, error) {
47		dbURL := os.Getenv("DATABASE_URL")
48		if dbURL == "" {
49			return nil, fmt.Errorf("DATABASE_URL is required")
50		}
51	
52		jwtKey := os.Getenv("JWT_SIGNING_KEY")
53		if jwtKey == "" {
54			return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
55		}
56	
57		aesKey, err := decodeAESKey(os.Getenv("AES_MASTER_KEY"))
58		if err != nil {
59			return nil, err
60		}
61	
62		return &Config{
63			ListenAddr:    listenAddr,
64			DatabaseURL:   dbURL,
65			JWTSigningKey: []byte(jwtKey),
66			AESMasterKey:  aesKey,
67		}, nil
68	}
69	
70	func loadFromKeyfile(listenAddr, path string) (*Config, error) {
71		passphrase := os.Getenv("SECRETS_PASSPHRASE")
72		if passphrase == "" {
73			return nil, fmt.Errorf("SECRETS_PASSPHRASE is required when using SECRETS_KEYFILE")
74		}
75	
76		ciphertext, err := os.ReadFile(path)
77		if err != nil {
78			return nil, fmt.Errorf("read keyfile %s: %w", path, err)
79		}
80	
81		plaintext, err := decryptKeyfile(ciphertext, passphrase)
82		if err != nil {
83			return nil, fmt.Errorf("decrypt keyfile: %w", err)
84		}
85	
86		var secrets secretsFile
87		if err := json.Unmarshal(plaintext, &secrets); err != nil {
88			return nil, fmt.Errorf("parse keyfile JSON: %w", err)
89		}
90	
91		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
92			return nil, fmt.Errorf("keyfile must contain database_url, jwt_signing_key, and aes_master_key")
93		}
94	
95		aesKey, err := decodeAESKey(secrets.AESMasterKey)
96		if err != nil {
97			return nil, err
98		}
99	
100		return &Config{
101			ListenAddr:    listenAddr,
102			DatabaseURL:   secrets.DatabaseURL,
103			JWTSigningKey: []byte(secrets.JWTSigningKey),
104			AESMasterKey:  aesKey,
105		}, nil
106	}
107	
108	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
109		key := sha256.Sum256([]byte(passphrase))
110		block, err := aes.NewCipher(key[:])
111		if err != nil {
112			return nil, err
113		}
114		gcm, err := cipher.NewGCM(block)
115		if err != nil {
116			return nil, err
117		}
118		nonceSize := gcm.NonceSize()
119		if len(ciphertext) < nonceSize {
120			return nil, fmt.Errorf("keyfile too short")
121		}
122		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
123		return gcm.Open(nil, nonce, ct, nil)
124	}
125	
