91			if err != nil {
92				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
93			}
94			defer dst.Close()
95	
96			if _, err := io.Copy(dst, src); err != nil {
97				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
98			}
99	
100			attachmentPath = dstPath
101			attachmentSize = int(file.Size)
102			attachmentMime = file.Header.Get("Content-Type")
103		}
104	
105		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
106			attachmentPath, attachmentSize, attachmentMime)
