{"replace_all": false, "file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/backend/internal/service/notification_service.go", "old_string": "func (s *NotificationService) Retry(ctx context.Context, id, userID uuid.UUID) error {
	notif, err := s.notifStore.GetByID(ctx, id)
	if err != nil {
		return err
	}
	if notif == nil {
		return dto.ErrNotFound
	}
	if notif.UserID != userID {
		return dto.ErrForbidden
	}
	if notif.Status != "failed" {
		return fmt.Errorf("%w: notification is not in failed state", dto.ErrValidation)
	}
	return s.notifStore.RetryNotification(ctx, id)
}", "new_string": "func (s *NotificationService) Retry(ctx context.Context, id, userID uuid.UUID) error {
	notif, err := s.notifStore.GetByID(ctx, id)
	if err != nil {
		return err
	}
	if notif == nil {
		return dto.ErrNotFound
	}
	if notif.UserID != userID {
		return dto.ErrForbidden
	}
	if notif.Status != "failed" && notif.Status != "permanently_failed" {
		return fmt.Errorf("%w: notification is not in a failed state", dto.ErrValidation)
	}
	// Manual retry resets to pending so the worker picks it up on the next tick.
	return s.notifStore.ResetToPending(ctx, id)
}"}

